app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Use a schema validator (e.g., zod or joi) for all input
const { z } = require('zod');

const CreateUserSchema = z.object({
  name: z.string().min(1).max(100),
  email: z.string().email()
});

app.post('/users', requireAuth, (req, res) => {
  const result = CreateUserSchema.safeParse(req.body);
  if (!result.success) {
    return res.status(400).json({ error: result.error.flatten() });
  }
  // safe to use result.data
});
```

---

## 🟡 Medium

### 5. No Security Logging or Monitoring (OWASP A09)

There is zero logging. Failed auth attempts, unexpected errors, or anomalous access patterns are completely invisible.

**Recommendation:**

```js
