    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    // safe to use req.params.id here
  }
);
```

---

#### 6. No CORS Policy — A05:2021
**No CORS middleware is configured.** Express will reflect permissive defaults in some environments. Cross-origin access to the `/users` endpoint should be explicitly controlled.

```js
// ✅ Fix — explicit CORS allowlist
const cors = require('cors');

const corsOptions = {
  origin: (origin, callback) => {
    const allowed = (process.env.ALLOWED_ORIGINS || '').split(',');
    if (!origin || allowed.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error(`CORS policy: origin ${origin} not allowed`));
    }
  },
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  credentials: true,
  maxAge: 86400, // Cache preflight for 24 hours
};

app.use(cors(corsOptions));
```

---

#### 7. Sensitive Data Exposure — A02:2021
**PII (email addresses) is returned wholesale without field filtering.** When connected to a real database, the API should return only the fields the caller is authorized to see.

```js
// ❌ Anti-pattern — returning raw DB row (exposes passwordHash, internal IDs, etc.)
app.get('/users', authenticateToken, async (req, res) => {
  const users = await db.query('SELECT * FROM users'); // ← never do this
  res.json(users);
});

// ✅ Fix — explicit projection / DTO pattern
app.get('/users', authenticateToken, async (req, res) => {
  const users = await db.query('SELECT id, name FROM users'); // email omitted unless needed
  res.json(users);
});
```

---

#### 8. No Error Handling & Information Leakage — A05:2021
**No global error handler.** Unhandled errors will cause Express to return default stack traces and internal paths to the client in development mode — and may crash the process entirely.

```js
// ✅ Fix — add a global error handler as the LAST middleware
app.use((err, req, res, next) => {
  // Log full error internally (use a real logger like winston/pino)
  console.error({ err, url: req.url, method: req.method });

  // Return a sanitized response — never leak stack traces
  const status = err.status || err.statusCode || 500;
  res.status(status).json({
    error: status < 500 ? err.message : 'An internal error occurred',
  });
});

// ✅ Also handle async route errors — wrap handlers or use express-async-errors
require('express-async-errors'); // patches Express to forward async rejections to above handler
```

---

#### 9. Security Logging & Monitoring Failures — A09:2021
**No logging of authentication events, access to sensitive data, or errors.** This makes incident detection and forensic investigation impossible.

```js
// ✅ Fix — structured logging with pino or winston
const pino = require('pino');
const logger = pino({ level: process.env.LOG_LEVEL || 'info' });

// Log security-relevant events explicitly
app.get('/users', authenticateToken, (req, res) => {
  logger.info({ event: 'users.list', actor: req.user.sub, ip: req.ip });
  // ...
});

// Log auth failures
if (!valid) {
  logger.warn({ event: 'auth.failure', username, ip: req.ip });
  return res.status(401).json({ error: 'Invalid credentials' });
}
```

---

### 🔵 Low / Informational

---

#### 10. `/health` Endpoint Timestamp — Minor Information Disclosure
The health endpoint returns the server's current time. While low-risk alone, accurate server time can assist timing-based attacks. Consider omitting it unless needed by load balancers.

```js
// ❌ Current
